function SR({ children, delay = 0, style = {}, effect = "up" }) {
  const [v, setV] = useState(false);
  const ref = useRef(null);
  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const o = new IntersectionObserver(([e]) => { if (e.isIntersecting) setV(true); }, { threshold: 0.1 });
    o.observe(el);
    return () => o.disconnect();
  }, []);
  const transforms = { up: "translateY(50px)", left: "translateX(-60px)", right: "translateX(60px)", scale: "scale(0.92)", blur: "translateY(20px)" };
  const from = transforms[effect] || transforms.up;
  const filterFrom = effect === "blur" ? "blur(8px)" : "blur(0px)";
  const filterTo = "blur(0px)";
  return <div ref={ref} style={{ opacity: v ? 1 : 0, transform: v ? "translateY(0) scale(1)" : from, filter: v ? filterTo : filterFrom, transition: `opacity 0.9s cubic-bezier(0.16,1,0.3,1) ${delay}s, transform 0.9s cubic-bezier(0.16,1,0.3,1) ${delay}s, filter 0.9s cubic-bezier(0.16,1,0.3,1) ${delay}s`, willChange: "opacity, transform, filter", ...style }}>{children}</div>;
}

function useParallax(speed = 0.5) {
  const ref = useRef(null);
  const [offset, setOffset] = useState(0);
  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const h = () => {
      const rect = el.getBoundingClientRect();
      const center = rect.top + rect.height / 2;
      const viewCenter = window.innerHeight / 2;
      setOffset((center - viewCenter) * speed * 0.15);
    };
    window.addEventListener("scroll", h, { passive: true });
    h();
    return () => window.removeEventListener("scroll", h);
  }, [speed]);
  return [ref, offset];
}


function useLerpScroll(ease = 0.08) {
  const wrapRef = useRef(null);
  const target = useRef(0);
  const current = useRef(0);
  const raf = useRef(null);
  const isTouch = useRef(false);

  useEffect(() => {
    isTouch.current = "ontouchstart" in window || navigator.maxTouchPoints > 0;
    if (isTouch.current) return; // native scroll on mobile

    const wrap = wrapRef.current;
    if (!wrap) return;

    // Lock the body, let the wrapper transform handle scrolling
    document.body.style.height = wrap.scrollHeight + "px";
    document.body.style.overflow = "auto";
    wrap.style.position = "fixed";
    wrap.style.top = "0";
    wrap.style.left = "0";
    wrap.style.width = "100%";
    wrap.style.willChange = "transform";

    const onResize = () => {
      document.body.style.height = wrap.scrollHeight + "px";
    };
    const ro = new ResizeObserver(onResize);
    ro.observe(wrap);

    const loop = () => {
      target.current = window.scrollY;
      current.current += (target.current - current.current) * ease;
      // Snap if close enough to avoid sub-pixel jitter
      if (Math.abs(target.current - current.current) < 0.5) {
        current.current = target.current;
      }
      wrap.style.transform = `translateY(${-current.current}px) translateZ(0)`;
      raf.current = requestAnimationFrame(loop);
    };
    raf.current = requestAnimationFrame(loop);

    return () => {
      cancelAnimationFrame(raf.current);
      ro.disconnect();
      document.body.style.height = "";
      document.body.style.overflow = "";
      if (wrap) {
        wrap.style.position = "";
        wrap.style.top = "";
        wrap.style.left = "";
        wrap.style.width = "";
        wrap.style.willChange = "";
        wrap.style.transform = "";
      }
    };
  }, [ease]);

  return wrapRef;
}

function Tilt3D({ children, intensity = 12, style = {} }) {
  const ref = useRef(null);
  const [rot, setRot] = useState({ x: 0, y: 0 });
  const [glow, setGlow] = useState({ x: 50, y: 50 });
  const handleMove = useCallback((e) => {
    const el = ref.current;
    if (!el) return;
    const rect = el.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width;
    const y = (e.clientY - rect.top) / rect.height;
    setRot({ x: (y - 0.5) * -intensity, y: (x - 0.5) * intensity });
    setGlow({ x: x * 100, y: y * 100 });
  }, [intensity]);
  const handleLeave = useCallback(() => { setRot({ x: 0, y: 0 }); setGlow({ x: 50, y: 50 }); }, []);
  return <div ref={ref} onMouseMove={handleMove} onMouseLeave={handleLeave} style={{ perspective: 800, ...style }}>
    <div style={{ transform: `rotateX(${rot.x}deg) rotateY(${rot.y}deg)`, transition: "transform 0.15s ease-out", position: "relative" }}>
      {children}
      <div style={{ position: "absolute", inset: 0, borderRadius: "inherit", background: `radial-gradient(circle at ${glow.x}% ${glow.y}%, rgba(34,211,238,0.12) 0%, transparent 60%)`, pointerEvents: "none", transition: "background 0.15s ease-out" }} />
    </div>
  </div>;
}

function DepthMeter({ scrollY }) {
  const maxScroll = typeof document !== "undefined" ? Math.max(document.body.scrollHeight - window.innerHeight, 1) : 1;
  const progress = Math.min(scrollY / maxScroll, 1);
  const depth = Math.round(progress * 33);
  const opacity = scrollY > 200 ? 0.7 : 0;
  return <div style={{ position: "fixed", right: "clamp(8px,2vw,24px)", top: "50%", transform: "translateY(-50%)", zIndex: 999, display: "flex", flexDirection: "column", alignItems: "center", gap: 8, opacity, transition: "opacity 0.5s", pointerEvents: "none" }}>
    <div style={{ width: 2, height: 120, borderRadius: 2, background: "rgba(255,255,255,0.08)", position: "relative", overflow: "hidden" }}>
      <div style={{ position: "absolute", bottom: 0, width: "100%", background: "linear-gradient(0deg, #22d3ee, #0891b2)", borderRadius: 2, height: `${progress * 100}%`, transition: "height 0.15s ease-out", boxShadow: "0 0 8px rgba(34,211,238,0.4)" }} />
    </div>
    <div style={{ writingMode: "vertical-lr", fontSize: 10, fontWeight: 600, letterSpacing: "0.1em", color: "#22d3ee", fontFamily: "'Outfit',sans-serif", textShadow: "0 0 8px rgba(34,211,238,0.4)" }}>{depth}m</div>
  </div>;
}

function Caustics({ scrollY }) {
  return <div style={{ position: "fixed", inset: 0, pointerEvents: "none", zIndex: 1, opacity: 0.035, mixBlendMode: "screen" }}>
    <svg width="100%" height="100%" style={{ position: "absolute", inset: 0 }}>
      <defs>
        <filter id="caustic-blur"><feGaussianBlur stdDeviation="18" /></filter>
      </defs>
      {[...Array(6)].map((_, i) => {
        const phase = (scrollY * (0.08 + i * 0.02)) + i * 120;
        const cx = 30 + Math.sin(phase * 0.01 + i) * 25;
        const cy = 20 + Math.cos(phase * 0.008 + i * 0.7) * 30;
        const r = 18 + Math.sin(phase * 0.005 + i * 2) * 8;
        return <circle key={i} cx={`${cx}%`} cy={`${cy}%`} r={`${r}%`} fill="rgba(34,211,238,0.5)" filter="url(#caustic-blur)" />;
      })}
    </svg>
  </div>;
}

function ScrollProgress({ scrollY }) {
  const maxScroll = typeof document !== "undefined" ? Math.max(document.body.scrollHeight - window.innerHeight, 1) : 1;
  const progress = Math.min(scrollY / maxScroll, 1);
  return <div style={{ position: "fixed", top: 0, left: 0, right: 0, height: 2, zIndex: 1001, pointerEvents: "none" }}>
    <div style={{ height: "100%", width: `${progress * 100}%`, background: "linear-gradient(90deg, #0891b2, #22d3ee)", boxShadow: "0 0 12px rgba(34,211,238,0.6)", transition: "width 0.08s linear" }} />
  </div>;
}

function AC({ value, suffix = "", label }) {
  const [count, setCount] = useState(0);
  const [go, setGo] = useState(false);
  const ref = useRef(null);
  useEffect(() => { const el = ref.current; if (!el) return; const o = new IntersectionObserver(([e]) => { if (e.isIntersecting) setGo(true); }, { threshold: 0.3 }); o.observe(el); return () => o.disconnect(); }, []);
  useEffect(() => { if (!go) return; let c = 0; const s = value / 80; const t = setInterval(() => { c += s; if (c >= value) { setCount(value); clearInterval(t); } else setCount(Math.floor(c)); }, 20); return () => clearInterval(t); }, [go, value]);
  return <div ref={ref} style={{ textAlign: "center" }}><div style={{ fontFamily: "'Syne',sans-serif", fontSize: "clamp(28px,5vw,56px)", fontWeight: 800, color: "white", lineHeight: 1 }}>{count}{suffix}</div><div style={{ fontSize: 14, color: "rgba(255,255,255,0.9)", marginTop: 8 }}>{label}</div></div>;
}

function PG({ images, labels }) {
  const [idx, setIdx] = useState(0);
  return <div><div style={{ borderRadius: 24, overflow: "hidden", border: "1px solid rgba(255,255,255,0.15)", boxShadow: "0 20px 60px rgba(0,0,0,0.4)" }}><img src={images[idx]} alt={labels[idx]} style={{ width: "100%", display: "block", aspectRatio: "1", objectFit: "cover" }} /></div>{images.length > 1 && <div style={{ display: "flex", gap: 8, justifyContent: "center", marginTop: 12 }}>{images.map((img, i) => <button key={i} onClick={() => setIdx(i)} style={{ width: 56, height: 56, borderRadius: 12, overflow: "hidden", border: idx === i ? "2px solid #22d3ee" : "2px solid rgba(255,255,255,0.1)", cursor: "pointer", padding: 0, background: "none", opacity: idx === i ? 1 : 0.5, transition: "all 0.3s", transform: idx === i ? "scale(1.05)" : "scale(1)" }}><img src={img} alt={labels[i]} style={{ width: "100%", height: "100%", objectFit: "cover" }} /></button>)}</div>}</div>;
}

function BgImg({ src, brightness = 1, position = "center", overlay = "rgba(2,10,24,0.85)", parallax = 0 }) {
  const mob = typeof window !== "undefined" && (window.innerWidth <= 768 || "ontouchstart" in window);
  return <><div style={{ position: "absolute", inset: mob ? 0 : "-10%", backgroundImage: `url(${src})`, backgroundSize: "cover", backgroundPosition: position, filter: `brightness(${brightness})`, ...(mob ? {} : { transform: `translate3d(0,${parallax}px,0) scale(1.05)`, transition: "transform 0.1s linear", willChange: "transform" }) }} /><div style={{ position: "absolute", inset: 0, background: `linear-gradient(180deg, #020a18 0%, ${overlay} 8%, rgba(2,10,24,0.15) 22%, transparent 38%, transparent 62%, rgba(2,10,24,0.15) 78%, ${overlay} 92%, #020a18 100%)` }} /></>;
}

